<template>
    <div>
        <section id="main-content" class="main-content">
            <loader :is-visible="isLoading"></loader>
            <div class="col-md-12 p-0">
                <div class="theme-primary partition-full">
                    <span class="p-name text-white">{{ $t('ManageCommunicationModes') }}</span>
                </div>
            </div>
            <div class="col-md-12 p-0">
                <div class="border p-3">
                    <dynamic-form lang="en" ref="form" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit">
                    </dynamic-form>
                    <div class="col-lg-6">
                        <div class="py-2"><small><span class="text-danger">
                                    {{ $t('MandatoryString') }}</span></small>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    </div>
</template>
<script>
import CommunicationModesDataService from "../../../services/DataService";
export default {
    data() {
        return {
            id: this.$route.params.id,
            modeTypeId: 0,
            isLoading: false,
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('communicationTypeName'),
                            name: "CommunicationTypeName",
                            value: "",
                            placeholder: this.$t('EntercommunicationTypeName'),
                            validationRules: { "required": true, max: 400 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Status'),
                            name: "Status",
                            value: "1001",
                            placeholder: "",
                            config: {
                                options: []
                            },
                        },
                    ],
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('DESCRIPTION'),
                            name: "CommunicationTypeDescription",
                            value: "",
                            placeholder: this.$t('EnterDescription'),
                            config: {
                                rows: 4,
                                cols: 7
                            },
                        }
                    ],
                }

            ],
            buttons: [
  {
    type: "submit",
    class: "btn btn-success save",
    text: `<i class='fa fa-save pr-2'></i> ${this.$t('submit')}`,
  },
  {
    type: "button",
    class: "btn btn-danger",
    text: `<i class='fa fa-close pr-2'></i> ${this.$t('Cancel')}`,
    onClick: this.onCancel
  }
],


        }
    },
    created: function () {
        this.GetStatusList("Views", "en");
        if (this.$route.params.id != 0) {
            this.EditCommunicationModeType(this.$route.params.id);
        }
    },
    methods: {
        onCancel: function () {
            this.$router.push({ name: 'CommunicationmodeList' });
        },
        goHome: function () {
            this.$router.push('/CommunicationModes/Index');
        },
        GetStatusList: function (StatusType, lang) {
            var vm = this;
            var url = "langCode=" + lang + "&statusType=" + StatusType + "&hasglobal=true";
            CommunicationModesDataService.GetStatusList(url).then(function (response) {
                response.data.forEach(element => {
                    let obj = {
                        name: element.status,
                        value: element.statuS_ID
                    }
                    vm.FormSchema[0].Data[1].config.options.push(obj);
                });
                vm.$refs.form.UpdateKeyValue();
            });
        },
        EditCommunicationModeType: function (id) {
            var vm = this;
            CommunicationModesDataService.GetCommunicationModeData(id).then(response => {
                if (response.data != null) {
                    vm.modeTypeId = response.data[0].modeTypeId;
                    vm.FormSchema[1].Data[0].value = response.data[0].communicationTypeDescription;
                    vm.FormSchema[0].Data[0].value = response.data[0].communicationTypeName;
                    vm.FormSchema[0].Data[1].value = response.data[0].statusId;
                }
            });
        },
        onSubmit(formfields, val) {            
            var vm = this;    
            vm.isLoading=true;           
            var jsonobj = {
                CommunicationTypeName: formfields.CommunicationTypeName,
                CommunicationTypeDescription: formfields.CommunicationTypeDescription,
                StatusId: formfields.Status,
                ModeTypeId: vm.modeTypeId,
            };                     
            var jobj = JSON.stringify(jsonobj);
            CommunicationModesDataService.CommunicationModesAdd(jobj).then((response) => {
                if (response.data == '0') {
                    vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t('CommunicationModes')]), "success", true, vm.$t("Alert"));
                    vm.goHome();
                }
                else if (response.data == '1') {
                  vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t('CommunicationModes')]), "success", true, vm.$t("Alert"));
                  vm.goHome();
                }
                else if (response.data == '2') {
                   vm.ShowAlert(vm.$t("AlreadyExists", [vm.$t('CommunicationModes')]), "warning", true, vm.$t("Alert"));
                }
                else {
                    vm.ShowAlert(vm.$t('AddedError', [vm.$t("CommunicationModes")]), "failure", true, vm.$t("Alert"));
                }
                vm.isLoading=false;
            })     
        }
    }
}
</script>